Code.Terraform:
```hcl
# VPC が複数のアベイラビリティーゾーンにまたがるように、異なる AZ に 2 つのサブネットを作成します
resource "aws_subnet" "subnet_a" {
  vpc_id            = "<example_resource_id>"
  cidr_block        = "10.0.0.0/24"
  availability_zone = "<example_az_1>" # 重要: 最初のAZ
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = "<example_resource_id>"
  cidr_block        = "10.0.1.0/24"
  availability_zone = "<example_az_2>" # 重要: 2つ目のAZ。サブネットが複数のAZにまたがることを保証します
}
```
